1	# Artifact cleanup module: functions for parsing artifacts, applying retention
2	# policies, and generating deletion plans.
3	
4	function ConvertTo-ArtifactList {
5	    [CmdletBinding()]
6	    param(
7	        [Parameter(Mandatory)]
8	        [string]$Json
9	    )
10	
11	    try {
12	        $raw = @($Json | ConvertFrom-Json)
13	    }
14	    catch {
15	        throw "Failed to parse artifact JSON: $($_.Exception.Message)"
16	    }
17	
18	    if ($raw.Count -eq 1 -and $null -eq $raw[0]) {
19	        return ,@()
20	    }
21	    if ($raw.Count -eq 0) {
22	        return ,@()
23	    }
24	
25	    $artifacts = [System.Collections.Generic.List[PSCustomObject]]::new()
26	    foreach ($item in $raw) {
27	        foreach ($field in @('Name', 'SizeBytes', 'CreatedDate', 'WorkflowRunId')) {
28	            if (-not $item.PSObject.Properties[$field]) {
29	                throw "Artifact missing required field '$field': $($item | ConvertTo-Json -Compress)"
30	            }
31	        }
32	        $artifacts.Add([PSCustomObject]@{
33	            Name          = [string]$item.Name
34	            SizeBytes     = [int64]$item.SizeBytes
35	            CreatedDate   = [datetime]$item.CreatedDate
36	            WorkflowRunId = [string]$item.WorkflowRunId
37	        })
38	    }
39	    return ,$artifacts.ToArray()
40	}
41	
42	function New-RetentionPolicy {
43	    [CmdletBinding()]
44	    param(
45	        [ValidateRange(0, [int]::MaxValue)]
46	        [int]$MaxAgeDays = 0,
47	
48	        [ValidateRange(0, [int64]::MaxValue)]
49	        [int64]$MaxTotalSizeBytes = 0,
50	
51	        [ValidateRange(0, [int]::MaxValue)]
52	        [int]$KeepLatestNPerWorkflow = 0
53	    )
54	
55	    return [PSCustomObject]@{
56	        MaxAgeDays             = $MaxAgeDays
57	        MaxTotalSizeBytes      = $MaxTotalSizeBytes
58	        KeepLatestNPerWorkflow = $KeepLatestNPerWorkflow
59	    }
60	}
61	
62	function Get-DeletionPlan {
63	    [CmdletBinding()]
64	    param(
65	        [AllowEmptyCollection()]
66	        [AllowNull()]
67	        [object[]]$Artifacts = @(),
68	
69	        [Parameter(Mandatory)]
70	        [object]$Policy,
71	
72	        [datetime]$ReferenceDate = (Get-Date),
73	
74	        [switch]$DryRun
75	    )
76	
77	    $mode = if ($DryRun) { "DRY-RUN" } else { "LIVE" }
78	
79	    if ($null -eq $Artifacts -or $Artifacts.Count -eq 0) {
80	        return [PSCustomObject]@{
81	            Mode              = $mode
82	            ReferenceDate     = $ReferenceDate
83	            TotalArtifacts    = 0
84	            DeletedCount      = 0
85	            RetainedCount     = 0
86	            SpaceReclaimed    = [int64]0
87	            SpaceRetained     = [int64]0
88	            DeletedArtifacts  = @()
89	            RetainedArtifacts = @()
90	        }
91	    }
92	
93	    $toDelete = @{}
94	    $retained = [ordered]@{}
95	
96	    foreach ($a in $Artifacts) {
97	        $retained[$a.Name] = $a
98	    }
99	
100	    # Pass 1: Remove artifacts exceeding max age
101	    if ($Policy.MaxAgeDays -gt 0) {
102	        $cutoff = $ReferenceDate.AddDays(-$Policy.MaxAgeDays)
103	        foreach ($a in $Artifacts) {
104	            if ($a.CreatedDate -lt $cutoff) {
105	                $ageDays = [math]::Floor(($ReferenceDate - $a.CreatedDate).TotalDays)
106	                $toDelete[$a.Name] = "exceeded max age of $($Policy.MaxAgeDays) days ($ageDays days old)"
107	                $retained.Remove($a.Name)
108	            }
109	        }
110	    }
111	
112	    # Pass 2: Keep only latest N per workflow
113	    if ($Policy.KeepLatestNPerWorkflow -gt 0) {
114	        $byWorkflow = @{}
115	        foreach ($a in $retained.Values) {
116	            if (-not $byWorkflow.ContainsKey($a.WorkflowRunId)) {
117	                $byWorkflow[$a.WorkflowRunId] = [System.Collections.Generic.List[object]]::new()
118	            }
119	            $byWorkflow[$a.WorkflowRunId].Add($a)
120	        }
121	        foreach ($wfId in @($byWorkflow.Keys)) {
122	            $sorted = @($byWorkflow[$wfId] | Sort-Object -Property CreatedDate -Descending)
123	            if ($sorted.Count -gt $Policy.KeepLatestNPerWorkflow) {
124	                $toRemove = @($sorted) | Select-Object -Skip $Policy.KeepLatestNPerWorkflow
125	                foreach ($a in $toRemove) {
126	                    $toDelete[$a.Name] = "exceeded keep-latest-$($Policy.KeepLatestNPerWorkflow) per workflow '$($a.WorkflowRunId)'"
127	                    $retained.Remove($a.Name)
128	                }
129	            }
130	        }
131	    }
132	
133	    # Pass 3: Enforce max total size by removing oldest retained artifacts
134	    if ($Policy.MaxTotalSizeBytes -gt 0) {
135	        $totalSize = ($retained.Values | Measure-Object -Property SizeBytes -Sum).Sum
136	        if ($null -eq $totalSize) { $totalSize = 0 }
137	        if ($totalSize -gt $Policy.MaxTotalSizeBytes) {
138	            $sortedByDate = @($retained.Values) | Sort-Object -Property CreatedDate
139	            foreach ($a in $sortedByDate) {
140	                if ($totalSize -le $Policy.MaxTotalSizeBytes) { break }
141	                $sizeMB = [math]::Round($Policy.MaxTotalSizeBytes / 1MB)
142	                $toDelete[$a.Name] = "exceeded max total size of $sizeMB MB"
143	                $retained.Remove($a.Name)
144	                $totalSize -= $a.SizeBytes
145	            }
146	        }
147	    }
148	
149	    # Build result arrays sorted by name for deterministic output
150	    $deletedArtifacts = @()
